public static void ExampleCreateDefaultDimension()
{
    DimensionDefault defaultDimension = IFRDimensionDefaultDimensionBuilder::construct()
        .addDimensionValue("B_Departamento", "COM")
        .addDimensionValue("D_Mercado", "NAC")
        .getDefaultDimension();
}

public static void ExampleCreateCustLedgerDimension()
{
    DimensionDynamicAccount ledgerDimension = IFRDimensionLedgerDimensionBuilderNonLedger::construct('CLIENTE01', LedgerJournalACType::Cust)
        .getLedgerDimension();
}

public static void ExampleCreateMainAccountLedgerDimension()
{
    DimensionDefault defaultDimension = 0; // TODO: Rellenar con las dimensiones.
    DimensionDynamicAccount ledgerDimension = IFRDimensionLedgerDimensionBuilderLedger::construct('43200000', defaultDimension)
        .getLedgerDimension();
}
